```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <memory>
#include <string>
#include <reaction/exceptions/cycle_exception.h>

namespace test_reaction {

// ============================================
// Data model definitions
// ============================================

class TestTransactionalObserver : public reaction::ObserverNode {
public:
    TestTransactionalObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

    void reset() {
        m_changed = false;
        m_callCount = 0;
    }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto source = std::make_shared<TestTransactionalObserver>("source");
    auto target = std::make_shared<TestTransactionalObserver>("target");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship
    graph.addObserver(source, target);

    // 4. Notify target and verify relationship works
    target->valueChanged(true);
    if (source->getCallCount() != 1) {
        return false; // Relationship not working
    }

    // 5. Reset observer for next test
    source->reset();
    target->reset();

    // 6. Attempt transactional update that would create cycle
    try {
        // This would create a cycle: source -> target -> source
        graph.addObserver(target, source);
        graph.updateObserversTransactional(source, {target}); // Transactional update
    } 
    // 7. Catch cycle exception if thrown
    catch (const reaction::CycleException& e) {
        // Cycle detected - transaction was rolled back
        return false;
    }

    // 8. Notify target again
    target->valueChanged(true);

    // 9. Verify original relationship is preserved
    if (source->getCallCount() != 1) { // Should still be 1 from initial notification
        return false; // Original relationship not preserved
    }

    // 10. Return success status
    return true; // No cycle detected, transaction succeeded
}

}  // namespace test_reaction
```

**Key implementation details:**

1. **Observer Nodes Creation**: Created `source` and `target` nodes using `std::make_shared`
2. **Graph Instance**: Retrieved singleton instance using `reaction::ObserverGraph::getInstance()`
3. **Initial Relationship**: Established `source` observes `target` using `addObserver`
4. **Relationship Verification**: Notified `target` and verified `source` received the change
5. **Reset**: Called `reset()` on both nodes to clear state for next test
6. **Transactional Update**: Attempted to create cycle by adding `target` observes `source`
7. **Exception Handling**: Caught `CycleException` if cycle was detected
8. **Second Notification**: Notified `target` again after failed transaction
9. **Preservation Check**: Verified original relationship wasn't affected by failed transaction
10. **Return Status**: Returns `true` if no cycle detected, `false` if cycle exception was caught

This implementation follows all the specified assessment objectives and uses the appropriate functions from the reaction library as documented in the reference materials.

