Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#pragma once

#include <reaction/reaction.h>
#include <cstdint>

namespace test_reaction {

struct AtomicCompoundSnapshot {
    int afterAddition;
    int afterMultiplication;
    int afterBitwiseAnd;
    int afterShift;
    int postIncrementReturn;
    int finalValue;
    int calcEvaluations;
};

/**
 * Function: Demonstrate atomic compound assignments on a reactive counter.
 *
 * @return AtomicCompoundSnapshot Snapshot with values after each compound operation.
 */
inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    REACTION_REGISTER_THREAD();

    // 1. Create a reactive variable (counter) with initial value 0
    auto counter = reaction::var(0);

    // 2. Create a counter for calculation evaluations
    auto calcCounter = reaction::var(0);

    // 3. Create a calculation that increments calcCounter and returns the current value
    auto calc = reaction::calc([&]() {
        calcCounter.value(calcCounter.get() + 1);
        return counter.get();
    });

    // 4. Apply atomic addition (+=) with value 5
    counter += 5;

    // 5. Get the value after addition
    int afterAddition = counter.get();

    // 6. Apply atomic multiplication (*=) with value 10
    counter *= 10;

    // 7. Get the value after multiplication
    int afterMultiplication = counter.get();

    // 8. Apply atomic bitwise AND (&=) with value 3
    counter &= 3;

    // 9. Get the value after bitwise AND
    int afterBitwiseAnd = counter.get();

    // 10. Apply atomic left shift (<<=) with value 1
    counter <<= 1;

    // 11. Get the value after shift
    int afterShift = counter.get();

    // 12. Apply post-increment (++) and store the returned old value
    int postIncrementReturn = counter++;

    // 13. Get the final value
    int finalValue = counter.get();

    // 14. Get the calculation evaluation count
    int calcEvaluations = calcCounter.get();

    // 15. Return a populated AtomicCompoundSnapshot
    return AtomicCompoundSnapshot{
        .afterAddition = afterAddition,
        .afterMultiplication = afterMultiplication,
        .afterBitwiseAnd = afterBitwiseAnd,
        .afterShift = afterShift,
        .postIncrementReturn = postIncrementReturn,
        .finalValue = finalValue,
        .calcEvaluations = calcEvaluations
    };
}

}  // namespace test_reaction
```

