inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    using namespace reaction;

    // 1. Create three reactive boolean variables using reaction::var
    auto var_a = var(a);
    auto var_b = var(b);
    auto var_c = var(c);

    // 2. Build AND expression: (a && b)
    auto and_expr = var_a && var_b;

    // 3. Build OR expression: (b || c)
    auto or_expr = var_b || var_c;

    // 4. Use reaction::expr to create reactive expressions from the logical operations
    auto reactive_and = expr(and_expr);
    auto reactive_or = expr(or_expr);

    // 5. Use get() method to retrieve initial values
    bool initial_and = reactive_and.get();
    bool initial_or = reactive_or.get();

